module RefModule(
  input signed [7:0] input_a,
  input signed [7:0] input_b,
  input reset,
  output signed [8:0] sum
);reg signed [8:0] sum_reg;

  always @(*) begin
    if (reset) begin
      sum_reg <= 0;
    end else begin
      sum_reg <= input_a + input_b;
    end
  end

  wire __sum_tmp = sum_reg;
  assign sum = __sum_tmp;

endmodule
